use distributed_inference::math::*;
use distributed_inference::matvec_memo;
use distributed_inference::model::{mat_vec_dispatch_batch, QType};
use std::time::Instant;

const QWEN_HIDDEN: usize = 896;
const QWEN_INTERMEDIATE: usize = 4864;
const QWEN_VOCAB: usize = 152_064;

fn arg_usize(flag: &str, default: usize) -> usize {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == flag {
            return args
                .next()
                .and_then(|value| value.parse::<usize>().ok())
                .unwrap_or(default);
        }
    }
    default
}

fn qwen_vocab_rows() -> usize {
    arg_usize("--vocab-rows", QWEN_VOCAB)
}

fn fill_q5_0_weights(w: &mut [u8]) {
    for (block_idx, block) in w.chunks_mut(22).enumerate() {
        block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
        let high = (0xa5a5_5a5au32 ^ (block_idx as u32).wrapping_mul(0x0101_0101)).to_le_bytes();
        block[2..6].copy_from_slice(&high);
        for (i, q) in block[6..22].iter_mut().enumerate() {
            *q = (i as u8)
                .wrapping_mul(17)
                .wrapping_add((block_idx % 251) as u8);
        }
    }
}

fn fill_q8_0_weights(w: &mut [u8]) {
    for (block_idx, block) in w.chunks_mut(34).enumerate() {
        block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
        for (i, q) in block[2..34].iter_mut().enumerate() {
            *q = (i as u8)
                .wrapping_mul(11)
                .wrapping_add((block_idx % 127) as u8);
        }
    }
}

fn fill_q4k_weights(w: &mut [u8]) {
    for (block_idx, block) in w.chunks_mut(144).enumerate() {
        block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
        block[2..4].copy_from_slice(&0x0000u16.to_le_bytes());
        for (i, scale) in block[4..16].iter_mut().enumerate() {
            *scale = (1 + ((i + block_idx) % 15)) as u8;
        }
        for (i, q) in block[16..144].iter_mut().enumerate() {
            *q = (i as u8)
                .wrapping_mul(17)
                .wrapping_add((block_idx % 251) as u8);
        }
    }
}

fn fill_q6k_weights(w: &mut [u8]) {
    for (block_idx, block) in w.chunks_mut(210).enumerate() {
        for (i, q) in block[0..192].iter_mut().enumerate() {
            *q = (i as u8)
                .wrapping_mul(13)
                .wrapping_add((block_idx % 251) as u8);
        }
        for (i, scale) in block[192..208].iter_mut().enumerate() {
            *scale = (1 + ((i + block_idx) % 7)) as u8;
        }
        block[208..210].copy_from_slice(&0x3c00u16.to_le_bytes());
    }
}

fn fill_q5k_weights(w: &mut [u8]) {
    for (block_idx, block) in w.chunks_mut(176).enumerate() {
        block[0..2].copy_from_slice(&0x3c00u16.to_le_bytes());
        block[2..4].copy_from_slice(&0x3800u16.to_le_bytes());
        for (i, scale) in block[4..16].iter_mut().enumerate() {
            *scale = ((1 + i + block_idx) % 63) as u8;
        }
        for (i, q) in block[16..176].iter_mut().enumerate() {
            *q = (i as u8)
                .wrapping_mul(19)
                .wrapping_add((block_idx % 251) as u8);
        }
    }
}

fn deterministic_input(cols: usize) -> Vec<f32> {
    (0..cols)
        .map(|i| (((i * 37 + 11) % 101) as f32 - 50.0) / 50.0)
        .collect()
}

fn run_case<F>(
    label: &str,
    rows: usize,
    cols: usize,
    bytes_per_row: usize,
    iters: usize,
    mut run: F,
) where
    F: FnMut(),
{
    run();
    let start = Instant::now();
    for _ in 0..iters {
        run();
    }
    let elapsed = start.elapsed();
    let per_call_us = elapsed.as_micros() as f64 / iters as f64;
    let per_call_ms = per_call_us / 1000.0;
    let bytes_read = (rows * bytes_per_row + cols * std::mem::size_of::<f32>()) as f64;
    let bw_gb_s = bytes_read / per_call_us * 1e6 / 1e9;
    println!(
        "{label}: rows={rows} cols={cols} {:.2} ms/call {:.1} GB/s",
        per_call_ms, bw_gb_s
    );
}

fn masked_context_hash(mask: &[u8], mask_role: u64) -> u64 {
    matvec_memo::hash_bytes(mask) ^ mask_role
}

#[allow(clippy::too_many_arguments)]
fn cached_masked_mat_vec(
    memo: &mut matvec_memo::MatVecMemo,
    out: &mut [f32],
    x: &[f32],
    w: &[u8],
    qtype: QType,
    rows: usize,
    cols: usize,
    layer: usize,
    op: u8,
    mask: &[u8],
    mask_role: u64,
    raw_dispatch: fn(&mut [f32], &[f32], &[u8], usize, usize, &[u8]),
) {
    let context_hash = masked_context_hash(mask, mask_role);
    let hit = memo
        .probe_with_context(layer, op, rows, cols, qtype, &x[..cols], context_hash)
        .map(|cached| cached.to_vec());
    if let Some(cached) = hit {
        out[..rows].copy_from_slice(&cached[..rows]);
        return;
    }

    raw_dispatch(out, x, w, rows, cols, mask);
    memo.insert_with_context(
        layer,
        op,
        rows,
        cols,
        qtype,
        &x[..cols],
        out[..rows].to_vec(),
        context_hash,
    );
}

#[allow(clippy::too_many_arguments)]
fn cached_q5_pair_output_masked(
    memo: &mut matvec_memo::MatVecMemo,
    out_gate: &mut [f32],
    out_up: &mut [f32],
    x: &[f32],
    gate_w: &[u8],
    up_w: &[u8],
    rows: usize,
    cols: usize,
    layer: usize,
    output_block_len: usize,
    output_block_mask: &[u8],
) {
    let context_hash = matvec_memo::hash_bytes(output_block_mask)
        ^ 0x0517_0B10_CAFE_u64
        ^ ((output_block_len as u64) << 32)
        ^ rows as u64;
    let gate_hit = memo
        .probe_with_context(
            layer,
            matvec_memo::OP_FFN_GATE,
            rows,
            cols,
            QType::Q5_0,
            &x[..cols],
            context_hash,
        )
        .map(|cached| cached.to_vec());
    let up_hit = memo
        .probe_with_context(
            layer,
            matvec_memo::OP_FFN_UP,
            rows,
            cols,
            QType::Q5_0,
            &x[..cols],
            context_hash,
        )
        .map(|cached| cached.to_vec());

    if let (Some(gate), Some(up)) = (gate_hit, up_hit) {
        out_gate[..rows].copy_from_slice(&gate[..rows]);
        out_up[..rows].copy_from_slice(&up[..rows]);
        return;
    }

    mat_vec_q5_0_pair_output_masked(
        out_gate,
        out_up,
        x,
        gate_w,
        up_w,
        rows,
        cols,
        output_block_len,
        output_block_mask,
    );
    memo.insert_with_context(
        layer,
        matvec_memo::OP_FFN_GATE,
        rows,
        cols,
        QType::Q5_0,
        &x[..cols],
        out_gate[..rows].to_vec(),
        context_hash,
    );
    memo.insert_with_context(
        layer,
        matvec_memo::OP_FFN_UP,
        rows,
        cols,
        QType::Q5_0,
        &x[..cols],
        out_up[..rows].to_vec(),
        context_hash,
    );
}

fn run_memo_case<F>(label: &str, iters: usize, mut run: F)
where
    F: FnMut(&mut matvec_memo::MatVecMemo),
{
    let mut memo = matvec_memo::MatVecMemo::new();
    memo.set_enabled(true);
    memo.set_tau_squared(0.0);
    memo.set_max_entries(8192);
    run(&mut memo);
    let cold_stats = memo.stats();

    let start = Instant::now();
    for _ in 0..iters {
        run(&mut memo);
    }
    let elapsed = start.elapsed();
    let warm_stats = memo.stats();
    let per_call_us = elapsed.as_micros() as f64 / iters as f64;
    println!(
        "{label}: warm={:.2} us/call stats cold={:?} warm={:?}",
        per_call_us, cold_stats, warm_stats
    );
}

fn main() {
    let iters = arg_usize("--iters", 20);
    let vocab_rows = qwen_vocab_rows();
    println!(
        "bench-matvec qwen dims: hidden={} intermediate={} vocab_rows={} iters={}",
        QWEN_HIDDEN, QWEN_INTERMEDIATE, vocab_rows, iters
    );

    let x_hidden = deterministic_input(QWEN_HIDDEN);
    let x_intermediate = deterministic_input(QWEN_INTERMEDIATE);

    let q5_bpr = QWEN_HIDDEN.div_ceil(32);
    let q5_bytes_per_row = q5_bpr * 22;
    let mut q5_w = vec![0u8; QWEN_INTERMEDIATE * q5_bytes_per_row];
    fill_q5_0_weights(&mut q5_w);
    let q5_w_b = q5_w.clone();
    let mut q5_out = vec![0.0f32; QWEN_INTERMEDIATE];
    let mut q5_out_b = vec![0.0f32; QWEN_INTERMEDIATE];
    run_case(
        "Q5_0 FFN gate/up",
        QWEN_INTERMEDIATE,
        QWEN_HIDDEN,
        q5_bytes_per_row,
        iters,
        || {
            mat_vec_q5_0(
                &mut q5_out,
                &x_hidden,
                &q5_w,
                QWEN_INTERMEDIATE,
                QWEN_HIDDEN,
            )
        },
    );
    run_case(
        "Q5_0 FFN gate/up paired",
        QWEN_INTERMEDIATE,
        QWEN_HIDDEN,
        q5_bytes_per_row * 2,
        iters,
        || {
            mat_vec_q5_0_pair(
                &mut q5_out,
                &mut q5_out_b,
                &x_hidden,
                &q5_w,
                &q5_w_b,
                QWEN_INTERMEDIATE,
                QWEN_HIDDEN,
            )
        },
    );
    let q5_mask: Vec<u8> = (0..QWEN_HIDDEN.div_ceil(32))
        .map(|i| if i % 4 == 3 { 0 } else { 1 })
        .collect();
    run_case(
        "Q5_0 FFN gate masked raw",
        QWEN_INTERMEDIATE,
        QWEN_HIDDEN,
        q5_bytes_per_row,
        iters,
        || {
            mat_vec_q5_0_masked(
                &mut q5_out,
                &x_hidden,
                &q5_w,
                QWEN_INTERMEDIATE,
                QWEN_HIDDEN,
                &q5_mask,
            )
        },
    );
    run_memo_case("Q5_0 FFN gate masked memo", iters, |memo| {
        cached_masked_mat_vec(
            memo,
            &mut q5_out,
            &x_hidden,
            &q5_w,
            QType::Q5_0,
            QWEN_INTERMEDIATE,
            QWEN_HIDDEN,
            0,
            matvec_memo::OP_FFN_GATE,
            &q5_mask,
            0x1A79_0001,
            mat_vec_q5_0_masked,
        )
    });
    let q5_output_mask: Vec<u8> = (0..QWEN_INTERMEDIATE.div_ceil(256))
        .map(|i| if i % 5 == 4 { 0 } else { 1 })
        .collect();
    run_case(
        "Q5_0 FFN gate/up output-masked paired raw",
        QWEN_INTERMEDIATE,
        QWEN_HIDDEN,
        q5_bytes_per_row * 2,
        iters,
        || {
            mat_vec_q5_0_pair_output_masked(
                &mut q5_out,
                &mut q5_out_b,
                &x_hidden,
                &q5_w,
                &q5_w_b,
                QWEN_INTERMEDIATE,
                QWEN_HIDDEN,
                256,
                &q5_output_mask,
            )
        },
    );
    run_memo_case(
        "Q5_0 FFN gate/up output-masked paired memo",
        iters,
        |memo| {
            cached_q5_pair_output_masked(
                memo,
                &mut q5_out,
                &mut q5_out_b,
                &x_hidden,
                &q5_w,
                &q5_w_b,
                QWEN_INTERMEDIATE,
                QWEN_HIDDEN,
                0,
                256,
                &q5_output_mask,
            )
        },
    );

    let q4_bpr = QWEN_INTERMEDIATE / 256;
    let q4_bytes_per_row = q4_bpr * 144;
    let mut q4_w = vec![0u8; QWEN_HIDDEN * q4_bytes_per_row];
    fill_q4k_weights(&mut q4_w);
    let mut q4_out = vec![0.0f32; QWEN_HIDDEN];
    run_case(
        "Q4_K FFN down",
        QWEN_HIDDEN,
        QWEN_INTERMEDIATE,
        q4_bytes_per_row,
        iters,
        || {
            mat_vec_q4k(
                &mut q4_out,
                &x_intermediate,
                &q4_w,
                QWEN_HIDDEN,
                QWEN_INTERMEDIATE,
            )
        },
    );
    let q4_mask: Vec<u8> = (0..(QWEN_INTERMEDIATE / 256))
        .map(|i| if i % 4 == 3 { 0 } else { 1 })
        .collect();
    run_case(
        "Q4_K FFN down masked raw",
        QWEN_HIDDEN,
        QWEN_INTERMEDIATE,
        q4_bytes_per_row,
        iters,
        || {
            mat_vec_q4k_masked(
                &mut q4_out,
                &x_intermediate,
                &q4_w,
                QWEN_HIDDEN,
                QWEN_INTERMEDIATE,
                &q4_mask,
            )
        },
    );
    run_memo_case("Q4_K FFN down masked memo", iters, |memo| {
        cached_masked_mat_vec(
            memo,
            &mut q4_out,
            &x_intermediate,
            &q4_w,
            QType::Q4K,
            QWEN_HIDDEN,
            QWEN_INTERMEDIATE,
            0,
            matvec_memo::OP_FFN_DOWN,
            &q4_mask,
            0xD0_0002,
            mat_vec_q4k_masked,
        )
    });

    let q6_bpr = QWEN_INTERMEDIATE / 256;
    let q6_bytes_per_row = q6_bpr * 210;
    let mut q6_w = vec![0u8; QWEN_HIDDEN * q6_bytes_per_row];
    fill_q6k_weights(&mut q6_w);
    let mut q6_out = vec![0.0f32; QWEN_HIDDEN];
    run_case(
        "Q6_K FFN down",
        QWEN_HIDDEN,
        QWEN_INTERMEDIATE,
        q6_bytes_per_row,
        iters,
        || {
            mat_vec_q6k(
                &mut q6_out,
                &x_intermediate,
                &q6_w,
                QWEN_HIDDEN,
                QWEN_INTERMEDIATE,
            )
        },
    );
    let q6_mask: Vec<u8> = (0..(QWEN_INTERMEDIATE / 256))
        .map(|i| if i % 4 == 3 { 0 } else { 1 })
        .collect();
    run_case(
        "Q6_K FFN down masked raw",
        QWEN_HIDDEN,
        QWEN_INTERMEDIATE,
        q6_bytes_per_row,
        iters,
        || {
            mat_vec_q6k_masked(
                &mut q6_out,
                &x_intermediate,
                &q6_w,
                QWEN_HIDDEN,
                QWEN_INTERMEDIATE,
                &q6_mask,
            )
        },
    );
    run_memo_case("Q6_K FFN down masked memo", iters, |memo| {
        cached_masked_mat_vec(
            memo,
            &mut q6_out,
            &x_intermediate,
            &q6_w,
            QType::Q6K,
            QWEN_HIDDEN,
            QWEN_INTERMEDIATE,
            0,
            matvec_memo::OP_FFN_DOWN,
            &q6_mask,
            0xD0_0002,
            mat_vec_q6k_masked,
        )
    });

    let q5k_bpr = QWEN_INTERMEDIATE / 256;
    let q5k_bytes_per_row = q5k_bpr * 176;
    let mut q5k_w = vec![0u8; QWEN_HIDDEN * q5k_bytes_per_row];
    fill_q5k_weights(&mut q5k_w);
    let mut q5k_out = vec![0.0f32; QWEN_HIDDEN];
    run_case(
        "Q5_K FFN down",
        QWEN_HIDDEN,
        QWEN_INTERMEDIATE,
        q5k_bytes_per_row,
        iters,
        || {
            mat_vec_q5k(
                &mut q5k_out,
                &x_intermediate,
                &q5k_w,
                QWEN_HIDDEN,
                QWEN_INTERMEDIATE,
            )
        },
    );

    let q8_bpr = QWEN_HIDDEN.div_ceil(32);
    let q8_bytes_per_row = q8_bpr * 34;
    let mut q8_w = vec![0u8; vocab_rows * q8_bytes_per_row];
    fill_q8_0_weights(&mut q8_w);
    let mut q8_out = vec![0.0f32; vocab_rows];
    run_case(
        "Q8_0 lm_head",
        vocab_rows,
        QWEN_HIDDEN,
        q8_bytes_per_row,
        iters.max(3) / 3,
        || mat_vec_q8_0(&mut q8_out, &x_hidden, &q8_w, vocab_rows, QWEN_HIDDEN),
    );
    run_memo_case("Q8_0 lm_head memo", iters, |memo| {
        matvec_memo::cached_mat_vec(
            memo,
            &mut q8_out,
            &x_hidden,
            &q8_w,
            QType::Q8_0,
            vocab_rows,
            QWEN_HIDDEN,
            1,
            vocab_rows,
            24,
            matvec_memo::OP_LM_HEAD,
            mat_vec_dispatch_batch,
        )
    });

    // ── Batched (prefill) shapes: the mat_vec_*_batch entry points ──────
    // Same weight tensors as above, n_batch lanes sharing them. This is the
    // batched-prefill hot path: the win to measure is weight decode amortized
    // across lanes vs re-decoded per lane.
    for &nb in &[8usize, 32] {
        let xs_q6: Vec<&[f32]> = (0..nb).map(|_| x_intermediate.as_slice()).collect();
        let mut q6_bouts: Vec<Vec<f32>> = vec![vec![0.0f32; QWEN_HIDDEN]; nb];
        run_case(
            &format!("Q6_K FFN down batch nb={nb}"),
            QWEN_HIDDEN,
            QWEN_INTERMEDIATE,
            q6_bytes_per_row,
            iters,
            || {
                let mut out_refs: Vec<&mut [f32]> =
                    q6_bouts.iter_mut().map(|v| v.as_mut_slice()).collect();
                mat_vec_q6k_batch(
                    &mut out_refs,
                    &xs_q6,
                    &q6_w,
                    QWEN_HIDDEN,
                    QWEN_INTERMEDIATE,
                );
            },
        );

        let xs_q5: Vec<&[f32]> = (0..nb).map(|_| x_hidden.as_slice()).collect();
        let mut q5_bouts: Vec<Vec<f32>> = vec![vec![0.0f32; QWEN_INTERMEDIATE]; nb];
        run_case(
            &format!("Q5_0 FFN gate batch nb={nb}"),
            QWEN_INTERMEDIATE,
            QWEN_HIDDEN,
            q5_bytes_per_row,
            iters,
            || {
                let mut out_refs: Vec<&mut [f32]> =
                    q5_bouts.iter_mut().map(|v| v.as_mut_slice()).collect();
                mat_vec_q5_0_batch(
                    &mut out_refs,
                    &xs_q5,
                    &q5_w,
                    QWEN_INTERMEDIATE,
                    QWEN_HIDDEN,
                );
            },
        );

        let xs_q8: Vec<&[f32]> = (0..nb).map(|_| x_hidden.as_slice()).collect();
        let q8_ffn_rows = QWEN_INTERMEDIATE;
        let mut q8_ffn_w = vec![0u8; q8_ffn_rows * q8_bytes_per_row];
        fill_q8_0_weights(&mut q8_ffn_w);
        let mut q8_bouts: Vec<Vec<f32>> = vec![vec![0.0f32; q8_ffn_rows]; nb];
        run_case(
            &format!("Q8_0 FFN gate batch nb={nb}"),
            q8_ffn_rows,
            QWEN_HIDDEN,
            q8_bytes_per_row,
            iters,
            || {
                let mut out_refs: Vec<&mut [f32]> =
                    q8_bouts.iter_mut().map(|v| v.as_mut_slice()).collect();
                mat_vec_q8_0_batch(&mut out_refs, &xs_q8, &q8_ffn_w, q8_ffn_rows, QWEN_HIDDEN);
            },
        );
    }
}
